import React from "react"
import moment from "moment";
import { properties } from '../../properties/properties.js'
var xlsx = require("xlsx");


class Scheduler extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedFile: null, totalBlock: 0, people: [], assignment: [], block: [], peopleOnly: [], assign: [], assignLeft: []
        };
    }

    handleselectedFile = event => {
        //console.log(event.target.files[0])
        this.setState({
          selectedFile: event.target.files[0]
        })
      }

    handleAddBlock = event => {

    }



    handleUpload = (e) => {

        this.setState({screen: 1})

        e.preventDefault();

        var reader = new FileReader();
        const scope = this;
        reader.onload = function (e) {


            function findV(cellValue) {
                var value_v = "";
                if (typeof cellValue !== 'undefined')
                    value_v = cellValue.v
                else
                    value_v = ""
                return value_v;
            }

            function findW(cellValue) {
                var value_w = "";
                if (typeof cellValue !== 'undefined') {
                    value_w = moment(cellValue.w,'M/D/YY').format('MM/DD/YYYY')

                } else {
                    value_w = ""
                }
                return value_w;
            }


            var data = e.target.result;
            let wb = xlsx.read(data, {type: 'binary'});
            //const wsname = readedData.SheetNames[0];
            //const ws = readedData.Sheets[wsname];
            var people = []

            var wsPeople = wb.Sheets[wb.SheetNames[0]];
            var wsAssignment = wb.Sheets[wb.SheetNames[1]];


            var rangePeople = xlsx.utils.decode_range(wsPeople['!ref']);
            var rangeAssignment = xlsx.utils.decode_range(wsAssignment['!ref']);

            var assignment = []
            var assign = []

            for (let colNum = 1; colNum <= rangeAssignment.e.c; colNum++) {
                var block = findV(wsAssignment[xlsx.utils.encode_cell({r: 0, c: colNum})])
