      findOnCall = (rec, rec2) => {

        var findAmionData = this.state.amionData.filter(amionRed => amionRed.name == rec2.name && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") >= moment(rec.startDate, "YYYY-MM-DD").add(-1, "M").format("YYYY-MM-DD") && moment(amionRed.date, "M-D-YY" ).format("YYYY-MM-DD") <= rec.startDate)

        findAmionData.sort(function(a,b) {
            return new Date(b.date) - new Date(a.date)
        })

        var onCallString = ""

        findAmionData.map(aDRec => {
            var before = rec2.before.split("|").map(item=>item.trim())

            before.map(bRec => {
                //console.log(bRec)
                if (bRec.toLowerCase() == "sf5r") {
                    if (aDRec.service.toLowerCase().includes("sf5r int long call") && onCallString == "") {
                        onCallString = moment(aDRec.date, "M-D-YY").format("MM/DD") + " on call"
                    }
                } else {
                    if (aDRec.service.toLowerCase().includes(bRec.toLowerCase()) && aDRec.service.toLowerCase() != bRec.toLowerCase() && onCallString == "") {
                        //console.log(findAmionData)
                        if (!aDRec.service.toLowerCase().includes("sfnfv x-cover")) {
                            onCallString = moment(aDRec.date, "M-D-YY").format("MM/DD") + " on call"
                        }
                    }
                }
            })

        })

        return onCallString

      }


